INSERT OR REPLACE INTO EnglishText (Tag, Text) VALUES
	('LOC_IMPROVEMENT_FARM_DESCRIPTION', 'Unlocks the Builder ability to construct Farm.[NEWLINE][NEWLINE]Must be built on Grassland or Plains.'),
	('LOC_IMPROVEMENT_MINE_DESCRIPTION', 'Unlocks the Builder ability to construct Mine.[NEWLINE][NEWLINE]Must be built on Hills or valid Resource.'),
	('LOC_IMPROVEMENT_QUARRY_DESCRIPTION', 'Unlocks the Builder ability to construct Quarry.[NEWLINE][NEWLINE]Must be built on valid Resource.'),
	('LOC_IMPROVEMENT_FISHING_BOATS_DESCRIPTION', 'Unlocks the Builder ability to construct Fishing Boats.[NEWLINE][NEWLINE]Must be built on valid Resource.'),
	('LOC_IMPROVEMENT_PASTURE_DESCRIPTION', 'Unlocks the Builder ability to construct Pasture.[NEWLINE][NEWLINE]Must be built on valid Resource.'),
	('LOC_IMPROVEMENT_CAMP_EXPANSION2_DESCRIPTION', 'Unlocks the Builder ability to construct Camp.[NEWLINE][NEWLINE]Must be built on valid Resource.'),
	('LOC_IMPROVEMENT_PLANTATION_DESCRIPTION', 'Unlocks the Builder ability to construct Plantation.[NEWLINE][NEWLINE]Must be built on valid Resource.'),
	('LOC_IMPROVEMENT_LUMBER_MILL_EXPANSION2_DESCRIPTION', 'Unlocks the Builder ability to construct Lumber Mill.[NEWLINE][NEWLINE]Must be built on Woods or Rainforest.'),
	('LOC_IMPROVEMENT_OIL_WELL_DESCRIPTION', 'Unlocks the Builder ability to construct Oil Well.[NEWLINE][NEWLINE]Must be built on land with [ICON_RESOURCE_OIL] Oil.'),
	('LOC_IMPROVEMENT_OFFSHORE_OIL_RIG_DESCRIPTION', 'Unlocks the Builder ability to construct Offshore Oil Rig.[NEWLINE][NEWLINE]Must be built on Coast or Lake with [ICON_RESOURCE_OIL] Oil.'),
	('LOC_IMPROVEMENT_FORT_DESCRIPTION', 'Unlocks the Military Engineer ability to construct Fort.[NEWLINE][NEWLINE]Occupying unit receives +4 [ICON_Strength] Defense Strength, and automatically gains 2 turns of fortification.'),
	('LOC_IMPROVEMENT_AIRSTRIP_DESCRIPTION', 'Unlocks the Military Engineer ability to construct Airstrip.[NEWLINE][NEWLINE]Can support 2 air units.[NEWLINE]Must be built on flat land.'),
	('LOC_IMPROVEMENT_MISSILE_SILO_DESCRIPTION', 'Unlocks the Military Engineer ability to construct Missile Silo.[NEWLINE][NEWLINE]Acts as a launch site for Nuclear and Thermonuclear Devices.'),
	('LOC_IMPROVEMENT_FISHERY_DESCRIPTION', 'Unlocks the Builder ability to construct Fisheries.[NEWLINE][NEWLINE]+1 [ICON_Food] Food for every adjacent sea Resource.[NEWLINE]Must be built on Coast.'),
	('LOC_IMPROVEMENT_CITY_PARK_DESCRIPTION', 'Unlocks the Builder ability to construct City Park.[NEWLINE][NEWLINE]+1 [ICON_Amenities] Amenity if adjacent to water.[NEWLINE]Cannot be built adjacent to another City Park.'),
	('LOC_IMPROVEMENT_SKI_RESORT_DESCRIPTION', 'Unlocks the Builder ability to construct Ski Resort.[NEWLINE][NEWLINE]Provides +4 [ICON_TOURISM] Tourism.[NEWLINE]Must be built on Mountain. Cannot be built adjacent to another Ski Resort. Cannot be pillaged, worked or removed.'),
	('LOC_IMPROVEMENT_BEACH_RESORT_DESCRIPTION', 'Unlocks the Builder ability to construct Seaside Resort.[NEWLINE][NEWLINE]Provides [ICON_Gold] Gold and [ICON_Tourism] Tourism equal to Appeal.[NEWLINE]Must be built on Grassland, Plains, or Desert without Hills adjacent to Coast. Minimum Appeal of Breathtaking.'),
	('LOC_IMPROVEMENT_MOUNTAIN_TUNNEL_DESCRIPTION', 'Unlocks the Military Engineer ability to construct Mountain Tunnel.[NEWLINE][NEWLINE]Can transport land units at cost of 2 [ICON_Movement] Movement.[NEWLINE]Must be built on Mountain. Cannot be pillaged or removed.'),
	('LOC_IMPROVEMENT_WIND_FARM_DESCRIPTION', 'Unlocks the Builder ability to construct Wind Farm.[NEWLINE][NEWLINE]Provides +2 [ICON_Power] Power per turn from renewable sources. Must be built on Hills.'),
	('LOC_IMPROVEMENT_OFFSHORE_WIND_FARM_DESCRIPTION', 'Unlocks the Builder ability to construct Offshore Wind Farm.[NEWLINE][NEWLINE]Provides +2 [ICON_Power] Power per turn from renewable sources. Must be built on Coast or Lake.'),
	('LOC_IMPROVEMENT_SOLAR_FARM_DESCRIPTION', 'Unlocks the Builder ability to construct Solar Farm.[NEWLINE][NEWLINE]Provides +2 [ICON_Power] Power per turn from renewable sources. Must be built on Grassland, Plains, Desert, or Tundra without Hills.'),
	('LOC_IMPROVEMENT_GEOTHERMAL_PLANT_DESCRIPTION', 'Unlocks the Builder ability to construct Geothermal Plant.[NEWLINE][NEWLINE]Provides +4 [ICON_Power] Power per turn from renewable sources. Must be built on Geothermal Fissure.'),
	('LOC_IMPROVEMENT_SEASTEAD_DESCRIPTION', 'Unlocks the Builder ability to construct Seastead.[NEWLINE][NEWLINE]+1 [ICON_Production] Production for every adjacent Fishing Boats. Fishing Boats receive +1 [ICON_Production] Production for every adjacent Seastead.[NEWLINE]+1 [ICON_Culture] Culture and [ICON_Tourism] Tourism for every adjacent Reef.[NEWLINE]Must be built on Coast, Lake or Ocean. Cannot be built adjacent to another Seastead.');
